     1→import { readFileSync } from "node:fs";
     2→import path from "node:path";
     3→import { AGENT_IDS } from "../types.ts";
     4→import type { AgentId, Manifest, SkillEntry } from "../types.ts";
     5→import { UserError } from "../errors.ts";
     6→
     7→export function loadManifest(directory: string): Manifest {
     8→  const manifestPath = path.join(directory, "inception.json");
     9→
    10→  let raw: string;
    11→  try {
    12→    raw = readFileSync(manifestPath, "utf-8");
    13→  } catch {
    14→    throw new UserError(
    15→      `No inception.json found in ${directory}. Are you pointing to the right repo?`
    16→    );
    17→  }
    18→
    19→  let parsed: unknown;
    20→  try {
    21→    parsed = JSON.parse(raw);
    22→  } catch {
    23→    throw new UserError(`Invalid JSON in ${manifestPath}`);
    24→  }
    25→
    26→  return validateManifest(parsed, manifestPath);
    27→}
    28→
    29→function validateManifest(data: unknown, filePath: string): Manifest {
    30→  if (typeof data !== "object" || data === null || Array.isArray(data)) {
    31→    throw new UserError(`${filePath}: manifest must be a JSON object`);
    32→  }
    33→
    34→  const obj = data as Record<string, unknown>;
    35→
    36→  if (!Array.isArray(obj.skills)) {
    37→    throw new UserError(`${filePath}: "skills" must be an array`);
    38→  }
    39→
    40→  const skills: SkillEntry[] = obj.skills.map((entry: unknown, i: number) => {
    41→    if (typeof entry !== "object" || entry === null || Array.isArray(entry)) {
    42→      throw new UserError(`${filePath}: skills[${i}] must be an object`);
    43→    }
    44→
    45→    const skill = entry as Record<string, unknown>;
    46→
    47→    if (typeof skill.name !== "string" || skill.name.length === 0) {
    48→      throw new UserError(`${filePath}: skills[${i}].name must be a non-empty string`);
    49→    }
    50→
    51→    const SAFE_NAME_RE = /^[a-zA-Z0-9][a-zA-Z0-9._-]*$/;
    52→    if (!SAFE_NAME_RE.test(skill.name as string)) {
    53→      throw new UserError(
    54→        `${filePath}: skills[${i}].name must contain only letters, digits, hyphens, underscores, and dots, and must not start with a dot`
    55→      );
    56→    }
    57→
    58→    if (typeof skill.path !== "string" || skill.path.length === 0) {
    59→      throw new UserError(`${filePath}: skills[${i}].path must be a non-empty string`);
    60→    }
    61→
    62→    if (path.isAbsolute(skill.path as string)) {
    63→      throw new UserError(`${filePath}: skills[${i}].path must be a relative path`);
    64→    }
    65→
    66→    if (!Array.isArray(skill.agents) || skill.agents.length === 0) {
    67→      throw new UserError(`${filePath}: skills[${i}].agents must be a non-empty array`);
    68→    }
    69→
    70→    for (const agent of skill.agents) {
    71→      if (!AGENT_IDS.includes(agent as AgentId)) {
    72→        throw new UserError(
    73→          `${filePath}: skills[${i}].agents contains unknown agent "${agent}". Valid agents: ${AGENT_IDS.join(", ")}`
    74→        );
    75→      }
    76→    }
    77→
    78→    return {
    79→      name: skill.name,
    80→      path: skill.path,
    81→      agents: skill.agents as AgentId[],
    82→    };
    83→  });
    84→
    85→  return {
    86→    skills,
    87→    mcpServers: Array.isArray(obj.mcpServers) ? obj.mcpServers : [],
    88→    agentRules: Array.isArray(obj.agentRules) ? obj.agentRules : [],
    89→  };
    90→}
    91→

