     6→import { planDeploy, executeDeploy } from "../src/core/deploy.ts";
     7→import type { Manifest } from "../src/types.ts";
     8→
     9→function makeTmpDir(): string {
    10→  const dir = path.join(os.tmpdir(), `ie-test-deploy-${Date.now()}-${Math.random().toString(36).slice(2)}`);
    11→  mkdirSync(dir, { recursive: true });
    12→  return dir;
    13→}
    14→
    15→function createSkillSource(baseDir: string, skillPath: string): string {
    16→  const fullPath = path.join(baseDir, skillPath);
    17→  mkdirSync(fullPath, { recursive: true });
    18→  writeFileSync(path.join(fullPath, "SKILL.md"), "---\nname: test\n---\n# Test");
    19→  return fullPath;
    20→}
    21→
    22→const testManifest: Manifest = {
    23→  skills: [
    24→    { name: "test-skill", path: "skills/test-skill", agents: ["claude-code", "codex"] },
    25→  ],
    26→  mcpServers: [],
    27→  agentRules: [],
    28→};
    29→
    30→describe("planDeploy", () => {
    31→  it("creates actions for detected agents only", () => {
    32→    const sourceDir = makeTmpDir();
    33→    try {
    34→      const actions = planDeploy(testManifest, sourceDir, ["claude-code"], "/home/test");
    35→      assert.equal(actions.length, 1);
    36→      assert.equal(actions[0]!.agent, "claude-code");
    37→      assert.equal(actions[0]!.skill, "test-skill");
    38→    } finally {
    39→      rmSync(sourceDir, { recursive: true });
    40→    }
    41→  });
    42→
    43→  it("creates actions for multiple agents", () => {
    44→    const sourceDir = makeTmpDir();
    45→    try {
    46→      const actions = planDeploy(testManifest, sourceDir, ["claude-code", "codex"], "/home/test");
    47→      assert.equal(actions.length, 2);
    48→    } finally {
    49→      rmSync(sourceDir, { recursive: true });
    50→    }
    51→  });
    52→
    53→  it("skips agents not in detected list", () => {
    54→    const sourceDir = makeTmpDir();
    55→    try {
    56→      const actions = planDeploy(testManifest, sourceDir, ["gemini-cli"], "/home/test");
    57→      assert.equal(actions.length, 0);
    58→    } finally {
    59→      rmSync(sourceDir, { recursive: true });
    60→    }
    61→  });
    62→});
    63→
    64→describe("executeDeploy", () => {
    65→  if (process.platform === "win32") return;
    66→
    67→  it("creates symlinks on POSIX", () => {
    68→    const sourceDir = makeTmpDir();
    69→    const home = makeTmpDir();
    70→    try {
    71→      createSkillSource(sourceDir, "skills/test-skill");
    72→      const actions = planDeploy(testManifest, sourceDir, ["claude-code"], home);
    73→      const { succeeded, failed } = executeDeploy(actions, false, false);
    74→
    75→      assert.equal(succeeded, 1);
    76→      assert.equal(failed.length, 0);
    77→
    78→      const target = actions[0]!.target;
    79→      assert.ok(existsSync(target));
    80→      assert.ok(lstatSync(target).isSymbolicLink());
    81→      assert.equal(readlinkSync(target), actions[0]!.source);
    82→    } finally {
    83→      rmSync(sourceDir, { recursive: true });
    84→      rmSync(home, { recursive: true, force: true });
    85→    }
    86→  });
    87→
    88→  it("does not create symlinks in dry-run mode", () => {
    89→    const sourceDir = makeTmpDir();
    90→    const home = makeTmpDir();
    91→    try {
    92→      createSkillSource(sourceDir, "skills/test-skill");
    93→      const actions = planDeploy(testManifest, sourceDir, ["claude-code"], home);
    94→      const { succeeded, failed } = executeDeploy(actions, true, false);
    95→
    96→      assert.equal(succeeded, 1);
    97→      assert.equal(failed.length, 0);
    98→
    99→      const target = actions[0]!.target;
   100→      assert.ok(!existsSync(target));
   101→    } finally {
   102→      rmSync(sourceDir, { recursive: true });
   103→      rmSync(home, { recursive: true, force: true });
   104→    }
   105→  });
   106→
   107→  it("overwrites existing symlink", () => {
   108→    const sourceDir = makeTmpDir();
   109→    const home = makeTmpDir();
   110→    try {
   111→      createSkillSource(sourceDir, "skills/test-skill");
   112→      const actions = planDeploy(testManifest, sourceDir, ["claude-code"], home);
   113→
   114→      // Deploy twice - second should overwrite
   115→      executeDeploy(actions, false, false);
   116→      const { succeeded, failed } = executeDeploy(actions, false, false);
   117→
   118→      assert.equal(succeeded, 1);
   119→      assert.equal(failed.length, 0);
   120→    } finally {
   121→      rmSync(sourceDir, { recursive: true });
   122→      rmSync(home, { recursive: true, force: true });
   123→    }
   124→  });
   125→
   126→  it("reports error for missing source", () => {
   127→    const home = makeTmpDir();
   128→    try {
   129→      const actions = planDeploy(testManifest, "/nonexistent/source", ["claude-code"], home);
   130→      const { succeeded, failed } = executeDeploy(actions, false, false);
   131→
   132→      assert.equal(succeeded, 0);
   133→      assert.equal(failed.length, 1);
   134→      assert.ok(failed[0]!.error.includes("Source not found"));
   135→    } finally {
   136→      rmSync(home, { recursive: true, force: true });
   137→    }
   138→  });
   139→});
